    // Test context() mode
    let response = pipeline.context("topic 0", "test-scope", None).await.unwrap();
    assert!(response.answer.is_none());
    assert!(response.context.metrics.sources_included > 0);
    assert!(response.context.context.contains("[1]")); // has citation markers
    assert!(response.trace.retrieval.retriever_name == "vector");
    assert!(response.trace.generation.is_none());
    assert!(response.trace.total_latency_ms < 5000);
